// @lat: [[crew#Pilot Exports]]
// @lat: [[crew#Event Day Export Packet]]
import { describe, expect, it } from "vitest"
import {
  CREW_ASSIGNMENT_CONFIRMATION_STATUS,
  CREW_ASSIGNMENT_CONFIRMATION_TYPE,
